def enviar_whatsapp(telefone, nome, itens, total, saldo_antes, saldo_depois, num_cupom):
    """Envia comprovante via WhatsApp usando n8n + Evolution API."""
    try:
        import urllib.request, json as _json
        from datetime import datetime as _dt

        # Formata telefone: garante 55 + DDD + número
        tel = str(telefone).strip().replace(" ", "").replace("-", "").replace("(", "").replace(")", "")
        if not tel.startswith("55"):
            tel = "55" + tel

        data_hora = _dt.now().strftime("%d/%m/%Y %H:%M:%S")
        qtd_total = sum(it.get("quantidade", 0) for it in itens)

        # Monta texto do comprovante
        linhas = [
            "━━━━━━━━━━━━━━━━━━━━━━━━",
            "🛒 *HOPE MARKET - COMPROVANTE*",
            "━━━━━━━━━━━━━━━━━━━━━━━━",
            f"*Cupom N:* {num_cupom:04d}",
            f"*Data:* {data_hora}",
            f"*Beneficiário:* {nome.upper()}",
            "━━━━━━━━━━━━━━━━━━━━━━━━",
            "*Itens da Cesta:*",
        ]
        for it in itens:
            linhas.append(f"  • {it['item']}: {it['quantidade']}x {it['valorUnitario']}HC = *{it['subtotal']}HC*")

        linhas += [
            "━━━━━━━━━━━━━━━━━━━━━━━━",
            f"📦 Total de itens: {qtd_total}",
            f"💰 *TOTAL GASTO: {total} HopeCoins*",
            f"Saldo anterior: {saldo_antes} HC",
            f"✅ *Saldo restante: {saldo_depois} HC*",
            "━━━━━━━━━━━━━━━━━━━━━━━━",
            "🙏 *Deus abençoe você!*",
            "Novos Começos Barra | HopeMarket",
        ]

        mensagem = "\n".join(linhas)

        payload = _json.dumps({
            "telefone": tel,
            "numero": tel,
            "message": mensagem,
            "mensagem": mensagem,
            "nome": nome,
            "beneficiario": nome,
            "itens": itens,
            "totalHopeCoins": total,
            "valorCarteira": saldo_antes,
            "saldoRestante": saldo_depois,
            "cupom": num_cupom,
            "data": data_hora,
        }).encode("utf-8")

        req = urllib.request.Request(
            N8N_WEBHOOK,
            data=payload,
            headers={"Content-Type": "application/json"},
            method="POST"
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            print(f"  [WhatsApp] Enviado para {tel} — status {resp.status}")
        return True
    except Exception as ex:
        print(f"  [WhatsApp] Erro: {ex}")
        return False

def conectar_sheets():
    creds = service_account.Credentials.from_service_account_file(
        CREDENCIAL_JSON, scopes=["https://www.googleapis.com/auth/spreadsheets"])
    return build("sheets", "v4", credentials=creds).spreadsheets()

def buscar_beneficiarios():
    try:
        res = conectar_sheets().values().get(
            spreadsheetId=SHEETS_ID, range=f"{ABA_CADASTRO}!A2:Z1000").execute()
        return res.get("values", [])
    except Exception as ex:
        log_erro("buscar_beneficiarios", str(ex))
        raise

def atualizar_sheets(linha_idx, novo_saldo, itens, hist_atual, row_atual):
    sheets = conectar_sheets()
    linha  = linha_idx + 2
    data_hora = datetime.now().strftime("%d/%m/%Y %H:%M")
    resumo    = ", ".join([f"{it['item']}({it['quantidade']})" for it in itens])
    novo_hist = f"{hist_atual}\n[{data_hora}] {resumo}".strip()
    sheets.values().update(
        spreadsheetId=SHEETS_ID, range=f"{ABA_CADASTRO}!C{linha}:D{linha}",
        valueInputOption="RAW", body={"values": [[novo_saldo, novo_hist]]}).execute()
    updates = []
    for i, nome_item in enumerate(ORDEM_ITENS_SHEETS):
        qtd_nova = next((it["quantidade"] for it in itens if it["item"] == nome_item), 0)
        if qtd_nova > 0:
            # Lê valor atual da planilha e SOMA
            col_idx = 5 + i  # coluna F = índice 5
            qtd_atual = 0
            if len(row_atual) > col_idx and row_atual[col_idx]:
                try:
                    qtd_atual = int(float(row_atual[col_idx]))
                except:
                    qtd_atual = 0
            qtd_total = qtd_atual + qtd_nova
            updates.append({
                "range": f"{ABA_CADASTRO}!{chr(ord('F')+i)}{linha}",
                "values": [[qtd_total]]
            })
    if updates:
        sheets.values().batchUpdate(
            spreadsheetId=SHEETS_ID,
            body={"valueInputOption": "RAW", "data": updates}).execute()


# ── VERIFICAÇÃO DE LIMITES MENSAIS ────────────────────────────────────────────
def obter_mes_atual():
    return datetime.now().strftime("%m/%Y")

def verificar_limites(row_dados, carrinho):
    """
    Verifica limites mensais consultando colunas F em diante da planilha.
    Retorna lista de itens que ultrapassam o limite.
    """
    problemas = []
    avisos = []

    # Colunas F em diante = índices 5+ na linha
    # ORDEM_ITENS_SHEETS[i] = coluna F+i
    for nome_item, qtd_nova in carrinho.items():
        if qtd_nova <= 0:
            continue

        idx = ORDEM_ITENS_SHEETS.index(nome_item) if nome_item in ORDEM_ITENS_SHEETS else -1
        col_idx = 5 + idx  # coluna F = índice 5

        # Quantidade já retirada este mês (da planilha)
        ja_retirado = 0
        if idx >= 0 and len(row_dados) > col_idx:
            try:
                ja_retirado = int(float(row_dados[col_idx])) if row_dados[col_idx] else 0
            except:
                ja_retirado = 0

        # Verificar café (limite em gramas)
        if nome_item in ["Café 100g", "Café 250g", "Café 500g"]:
            gramas_item = int(nome_item.replace("Café ", "").replace("g", ""))
            gramas_nova = gramas_item * qtd_nova
            gramas_ja   = gramas_item * ja_retirado  # simplificado

            # Soma total de gramas de café já retiradas
            gramas_total_ja = 0
            for cafe_nome in ["Café 100g", "Café 250g", "Café 500g"]:
                if cafe_nome in ORDEM_ITENS_SHEETS:
                    ci = ORDEM_ITENS_SHEETS.index(cafe_nome)
                    ci_col = 5 + ci
                    if len(row_dados) > ci_col and row_dados[ci_col]:
                        try:
                            g_cafe = int(cafe_nome.replace("Café ", "").replace("g", ""))
                            gramas_total_ja += g_cafe * int(float(row_dados[ci_col]))
                        except:
                            pass

            total_cafe = gramas_total_ja + gramas_nova
            if total_cafe > LIMITE_CAFE_GRAMAS:
                excesso = total_cafe - LIMITE_CAFE_GRAMAS
                problemas.append({
                    "item": f"Café (total)",
                    "ja_retirado": f"{gramas_total_ja}g",
                    "solicitando": f"{gramas_nova}g",
                    "total": f"{total_cafe}g",
                    "limite": f"{LIMITE_CAFE_GRAMAS}g",
                    "excesso": f"{excesso}g"
                })
            continue

        # Demais itens
        limite = LIMITES_MENSAIS.get(nome_item)
        if limite is None:
            continue

        total_novo = ja_retirado + qtd_nova
        if total_novo > limite:
            excesso = total_novo - limite
            problemas.append({
                "item": nome_item,
                "ja_retirado": ja_retirado,
                "solicitando": qtd_nova,
                "total": total_novo,
                "limite": limite,
                "excesso": excesso
            })
        elif ja_retirado > 0:
            avisos.append(f"{nome_item}: já retirou {ja_retirado}/{limite}")

    return problemas, avisos




# ── FUNÇÕES DE ESTOQUE ────────────────────────────────────────────────────────
def conectar_sheets_estoque():
    creds = service_account.Credentials.from_service_account_file(
        CREDENCIAL_JSON, scopes=["https://www.googleapis.com/auth/spreadsheets"])
    return build("sheets", "v4", credentials=creds).spreadsheets()

def _normalizar(s):
    """Remove espaços extras e converte para minúsculas para comparação."""
    return s.strip().lower()

def buscar_estoque():
    """Busca todos os itens do estoque. Retorna dict com nome original como chave."""
    try:
        res = conectar_sheets_estoque().values().get(
            spreadsheetId=ESTOQUE_SHEETS_ID,
            range=f"{ABA_ESTOQUE}!A1:C1000").execute()
        rows = res.get("values", [])
        estoque = {}
        for i, row in enumerate(rows):
            nome_bruto = row[0].strip() if len(row) > 0 and row[0] else None
            if not nome_bruto or nome_bruto.upper() in ("ITEM", "ESTOQUE"):
                continue  # pula cabeçalho
            qtd    = int(float(row[1])) if len(row) > 1 and row[1] else 0
            minimo = int(float(row[2])) if len(row) > 2 and row[2] else ESTOQUE_MINIMO_PADRAO
            # Guarda com nome da planilha mas indexa também pelo nome normalizado
            estoque[nome_bruto] = {
                "qtd": qtd, "minimo": minimo, "linha": i + 1,
                "nome_lower": _normalizar(nome_bruto)
            }
        return estoque
    except Exception as ex:
        print(f"[Estoque] Erro ao buscar: {ex}")
        return {}

def _buscar_item_estoque(estoque, nome_pdv):
    """Encontra item no estoque ignorando maiúsculas e espaços."""
    chave_lower = _normalizar(nome_pdv)
    for nome, dados in estoque.items():
        if dados["nome_lower"] == chave_lower:
            return nome, dados
    return None, None

def descontar_estoque(itens_comprados):
    """Desconta do estoque os itens comprados. itens_comprados = [{item, quantidade}]"""
    try:
        sheets  = conectar_sheets_estoque()
        # Busca planilha inteira para encontrar linhas mesmo com col B vazia
        res = sheets.values().get(
            spreadsheetId=ESTOQUE_SHEETS_ID,
            range=f"{ABA_ESTOQUE}!A1:C1000").execute()
        rows = res.get("values", [])

        # Monta mapa: nome_lower -> numero_da_linha_real
        mapa = {}
        for i, row in enumerate(rows):
            if not row or not row[0].strip():
                continue
            nome_bruto = row[0].strip()
            if nome_bruto.upper() in ("ITEM", "ESTOQUE", "QUANTIDADE", "MINIMO"):
                continue
            qtd = int(float(row[1])) if len(row) > 1 and row[1] else 0
            mapa[nome_bruto.lower()] = {"nome": nome_bruto, "qtd": qtd, "linha": i + 1}

        updates = []
        for it in itens_comprados:
            nome_pdv = it["item"].strip().lower()
            qtd      = it["quantidade"]
            dados    = mapa.get(nome_pdv)
            if dados:
                nova_qtd = max(0, dados["qtd"] - qtd)
                updates.append({
                    "range": f"{ABA_ESTOQUE}!B{dados['linha']}",
                    "values": [[nova_qtd]]
                })
                print(f"[Estoque] {dados['nome']}: {dados['qtd']} -> {nova_qtd}")
            else:
                print(f"[Estoque] Nao encontrado: '{it['item']}'  | Chaves: {list(mapa.keys())[:5]}")

        if updates:
            sheets.values().batchUpdate(
                spreadsheetId=ESTOQUE_SHEETS_ID,
                body={"valueInputOption": "RAW", "data": updates}).execute()
            print(f"[Estoque] {len(updates)} itens descontados com sucesso")
    except Exception as ex:
        print(f"[Estoque] Erro ao descontar: {ex}")

def atualizar_qtd_estoque(nome_item, nova_qtd, linha):
    """Atualiza a quantidade de um item buscando a linha pelo nome na col A."""
    try:
        sheets = conectar_sheets_estoque()
        # Lê só coluna A para achar a linha certa pelo nome
        res = sheets.values().get(
            spreadsheetId=ESTOQUE_SHEETS_ID,
            range=f"{ABA_ESTOQUE}!A1:A1000",
            valueRenderOption="UNFORMATTED_VALUE").execute()
        rows = res.get("values", [])
        linha_real = None
        for i, row in enumerate(rows):
            celula = row[0].strip() if row else ""
            if celula.lower() == nome_item.strip().lower():
                linha_real = i + 1
                break
        if linha_real is None:
            print(f"[Estoque] Nao achou '{nome_item}' na col A, usando linha {linha}")
            linha_real = linha

        # Escreve diretamente usando USER_ENTERED para garantir que cria a célula
        sheets.values().update(
            spreadsheetId=ESTOQUE_SHEETS_ID,
            range=f"{ABA_ESTOQUE}!B{linha_real}",
            valueInputOption="USER_ENTERED",
            body={"values": [[nova_qtd]]}).execute()
        print(f"[Estoque] SALVO: {nome_item} = {nova_qtd} na linha {linha_real}")
        return True
    except Exception as ex:
        print(f"[Estoque] Erro ao atualizar '{nome_item}': {ex}")
        return False
        return False

def inicializar_aba_estoque():
    """Cria a aba Estoque com os itens se ela não existir."""
    try:
        sheets = conectar_sheets_estoque()
        # Verifica se a aba já existe
        meta = sheets.get(spreadsheetId=ESTOQUE_SHEETS_ID).execute()
        abas = [s["properties"]["title"] for s in meta.get("sheets", [])]
        if ABA_ESTOQUE not in abas:
            # Cria a aba
            sheets.batchUpdate(
                spreadsheetId=ESTOQUE_SHEETS_ID,
                body={"requests": [{"addSheet": {"properties": {"title": ABA_ESTOQUE}}}]}
            ).execute()
        # Verifica se tem cabeçalho
        res = sheets.values().get(
            spreadsheetId=ESTOQUE_SHEETS_ID,
            range=f"{ABA_ESTOQUE}!A1:C1").execute()
        if not res.get("values"):
            # Insere cabeçalho e itens zerados
            cabecalho = [["Item", "Quantidade", "Mínimo"]]
            itens = [[nome, 0, ESTOQUE_MINIMO_PADRAO] for nome in ORDEM_ITENS_SHEETS]
            sheets.values().update(
                spreadsheetId=ESTOQUE_SHEETS_ID,
                range=f"{ABA_ESTOQUE}!A1",
                valueInputOption="RAW",
                body={"values": cabecalho + itens}).execute()
            print("[Estoque] Aba inicializada com itens!")
        return True
    except Exception as ex:
        print(f"[Estoque] Erro ao inicializar aba: {ex}")
        return False



