# FUNÇÕES DE RELATÓRIO
# ══════════════════════════════════════════════════════════════════════════════

def buscar_dados_relatorio():
    """Lê planilha e retorna dados processados para relatórios."""
    try:
        res = conectar_sheets().values().get(
            spreadsheetId=SHEETS_ID,
            range=f"{ABA_CADASTRO}!A2:Z1000").execute()
        rows = res.get("values", [])
    except Exception as ex:
        log_erro("Relatorio", f"Erro ao buscar planilha: {ex}")
        return None

    mes_atual = datetime.now().strftime("%m/%Y")
    total_hc_mes     = 0
    total_atend_mes  = 0
    itens_count      = {nome: 0 for nome in ORDEM_ITENS_SHEETS}
    benef_ativos     = []

    for row in rows:
        if not row: continue
        nome  = row[0] if len(row) > 0 else ""
        saldo = row[2] if len(row) > 2 else ""
        hist  = row[3] if len(row) > 3 else ""

        # Conta atendimentos do mes atual
        atend_mes = 0
        hc_mes    = 0
        if hist:
            for linha_hist in hist.split("\n"):
                if mes_atual in linha_hist:
                    atend_mes += 1

        # Soma itens distribuídos (colunas F em diante)
        total_itens_benef = 0
        for i, nome_item in enumerate(ORDEM_ITENS_SHEETS):
            col_idx = 5 + i
            if len(row) > col_idx and row[col_idx]:
                try:
                    qtd = int(float(row[col_idx]))
                    itens_count[nome_item] += qtd
                    total_itens_benef += qtd
                except: pass

        if atend_mes > 0:
            total_atend_mes += atend_mes
            benef_ativos.append((nome, atend_mes, total_itens_benef))

    # Ordena beneficiarios mais ativos
    benef_ativos.sort(key=lambda x: x[1], reverse=True)

    # Itens mais distribuídos
    itens_ordenados = sorted(itens_count.items(), key=lambda x: x[1], reverse=True)

    return {
        "mes":           mes_atual,
        "total_benef":   len(rows),
        "atend_mes":     total_atend_mes,
        "itens":         itens_ordenados,
        "benef_ativos":  benef_ativos[:10],
        "itens_count":   itens_count,
    }


def imprimir_relatorio(dados, impressora=None):
    """Imprime relatório na impressora térmica."""
    try:
        import win32print, win32ui, win32con
        nome_imp = impressora or win32print.GetDefaultPrinter()
        dc = win32ui.CreateDC()
        dc.CreatePrinterDC(nome_imp)

        fonte_p = win32ui.CreateFont({"name": "Arial", "height": 22, "weight": win32con.FW_NORMAL, "charset": 0})
        fonte_n = win32ui.CreateFont({"name": "Arial", "height": 26, "weight": win32con.FW_NORMAL, "charset": 0})
        fonte_b = win32ui.CreateFont({"name": "Arial", "height": 26, "weight": win32con.FW_BOLD,   "charset": 0})
        fonte_g = win32ui.CreateFont({"name": "Arial", "height": 36, "weight": win32con.FW_BOLD,   "charset": 0})

        dc.StartDoc("Relatorio HopeMarket")
        dc.StartPage()

        MARGEM_X = 10
        LARGURA  = 550
        y        = 20
        LINHA    = 32

        def txt(t, fonte=None, centro=False):
            nonlocal y
            f = fonte or fonte_n
            dc.SelectObject(f)
            if centro:
                lw = dc.GetTextExtent(t)[0]
                x = MARGEM_X + (LARGURA - lw) // 2
            else:
                x = MARGEM_X
            dc.TextOut(x, y, t)
            y += LINHA

        def sep():
            nonlocal y
            pen = win32ui.CreatePen(win32con.PS_SOLID, 1, 0)
            dc.SelectObject(pen)
            dc.MoveTo(MARGEM_X, y+4); dc.LineTo(MARGEM_X+LARGURA, y+4)
            y += 20

        txt("HOPE MARKET PDV", fonte_g, centro=True)
        txt(f"Relatorio - {NOME_UNIDADE}", fonte_b, centro=True)
        txt(datetime.now().strftime("%d/%m/%Y %H:%M"), fonte_p, centro=True)
        sep()

        txt(f"Mes: {dados['mes']}", fonte_b)
        txt(f"Total beneficiarios: {dados['total_benef']}", fonte_n)
        txt(f"Atendimentos no mes: {dados['atend_mes']}", fonte_n)
        sep()

        txt("TOP 10 ITENS DISTRIBUIDOS:", fonte_b)
        for i, (item, qtd) in enumerate(dados["itens"][:10], 1):
            if qtd > 0:
                txt(f"  {i}. {item}: {qtd} unid", fonte_p)
        sep()

        txt("BENEFICIARIOS MAIS ATIVOS:", fonte_b)
        for nome, atend, itens_t in dados["benef_ativos"][:5]:
            txt(f"  {nome[:22]}: {atend}x", fonte_p)
        sep()

        txt("RuahSystems | Berg Braga", fonte_p, centro=True)

        dc.EndPage()
        dc.EndDoc()
        dc.DeleteDC()
        return True
    except Exception as ex:
        log_erro("ImprimirRelatorio", str(ex))
        return False

# ── JANELA DE CONFIGURAÇÕES ───────────────────────────────────────────────────
class JanelaConfig(tk.Toplevel):
    def __init__(self, parent, cfg, callback):
        super().__init__(parent)
        self.title("Configurações - Impressora")
        self.configure(bg=BG2)
        self.resizable(False, False)
        self.grab_set()
        self.cfg = cfg
        self.callback = callback

        tk.Label(self, text="🖨️  Configurar Impressora", font=("Georgia", 14, "bold"),
                 bg=BG2, fg=OFFWHITE).pack(padx=24, pady=(20, 4))
        tk.Label(self, text="Selecione a impressora para comprovantes:",
                 font=("Courier", 10), bg=BG2, fg=CINZA).pack(padx=24)

        self.var_imp = tk.StringVar(value=cfg.get("impressora", ""))
        frame_sel = tk.Frame(self, bg=BG2)
        frame_sel.pack(fill="x", padx=24, pady=10)

        self.combo = ttk.Combobox(frame_sel, textvariable=self.var_imp,
                                   font=("Courier", 11), width=40)
        self.combo.pack(side="left", expand=True, fill="x")

        tk.Button(frame_sel, text="🔄", bg=BG3, fg=OFFWHITE, relief="flat",
                  font=("Courier", 12), command=self._atualizar_lista,
                  padx=6).pack(side="left", padx=(6, 0))

        self.lbl_status = tk.Label(self, text="", font=("Courier", 9),
                                    bg=BG2, fg=CINZA)
        self.lbl_status.pack()

        frame_btn = tk.Frame(self, bg=BG2)
        frame_btn.pack(fill="x", padx=24, pady=(4, 20))
        tk.Button(frame_btn, text="💾  Salvar", font=("Georgia", 11, "bold"),
                  bg=VERDE2, fg=OFFWHITE, relief="flat", pady=8,
                  command=self._salvar).pack(side="right", padx=(6, 0))
        tk.Button(frame_btn, text="🖨️  Testar", font=("Georgia", 11),
                  bg=BG3, fg=OFFWHITE, relief="flat", pady=8,
                  command=self._testar).pack(side="right")

        self._atualizar_lista()

    def _atualizar_lista(self):
        self.lbl_status.config(text="Buscando impressoras...", fg=AMARELO)
        def buscar():
            impressoras = listar_impressoras()
            self.after(0, lambda: self._preencher(impressoras))
        threading.Thread(target=buscar, daemon=True).start()

    def _preencher(self, impressoras):
        self.combo["values"] = impressoras
        if impressoras:
            self.lbl_status.config(text=f"{len(impressoras)} impressora(s) encontrada(s)", fg=VERDE)
            if not self.var_imp.get() and impressoras:
                self.var_imp.set(impressoras[0])
        else:
            self.lbl_status.config(text="Nenhuma impressora encontrada", fg=VERMELHO)

    def _salvar(self):
        self.cfg["impressora"] = self.var_imp.get()
        salvar_config(self.cfg)
        self.callback(self.cfg)
        self.destroy()
        messagebox.showinfo("✓", f"Impressora salva:\n{self.var_imp.get() or '(padrão do sistema)'}")

    def _testar(self):
        imp = self.var_imp.get()
        self.lbl_status.config(text="Enviando teste...", fg=AMARELO)
        def teste():
            resultado = imprimir_comprovante(
                "TESTE", [{"item": "Teste Item", "quantidade": 1, "subtotal": 10}],
                10, 100, 90, imp
            )
            msg = "✓ Teste enviado!" if resultado is True else f"Erro: {resultado}"
            cor = VERDE if resultado is True else VERMELHO
            self.after(0, lambda: self.lbl_status.config(text=msg, fg=cor))
        threading.Thread(target=teste, daemon=True).start()


