# SISTEMA DE ATUALIZAÇÃO AUTOMÁTICA
# ══════════════════════════════════════════════════════════════════════════════

def verificar_atualizacao(callback_resultado):
    """Verifica silenciosamente se há versão nova no GitHub."""
    def check():
        try:
            # Lê versão local (salva após atualização) ou usa VERSAO_ATUAL
            versao_local_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "versao_local.txt")
            if os.path.exists(versao_local_path):
                with open(versao_local_path) as vf:
                    versao_base = vf.read().strip()
            else:
                versao_base = VERSAO_ATUAL

            print(f"[Update] Verificando versao em: {VERSION_URL}")
            resp = requests.get(VERSION_URL, timeout=5)
            versao_nova = resp.text.strip()
            print(f"[Update] Versao atual: {versao_base} | Versao GitHub: {versao_nova}")
            if resp.status_code == 200:
                if versao_nova != versao_base:
                    print(f"[Update] Nova versao disponivel: {versao_nova}")
                    callback_resultado(versao_nova)
                else:
                    print("[Update] Sistema ja esta na versao mais recente.")
                    callback_resultado(None)
            else:
                print(f"[Update] Erro HTTP: {resp.status_code}")
                callback_resultado(None)
        except Exception as ex:
            print(f"[Update] Erro ao verificar: {ex}")
            callback_resultado(None)
    threading.Thread(target=check, daemon=True).start()


def baixar_atualizacao(versao_nova, callback_progresso, callback_concluido):
    """Baixa o novo arquivo e substitui o atual."""
    def download():
        try:
            callback_progresso("Baixando atualização...")
            resp = requests.get(UPDATE_URL, timeout=30, stream=True)
            if resp.status_code != 200:
                callback_concluido(False, "Erro ao baixar: servidor retornou erro.")
                return

            arquivo_atual = os.path.abspath(__file__)
            arquivo_backup = arquivo_atual + ".bak"
            arquivo_temp   = arquivo_atual + ".new"

            # Salva novo arquivo
            with open(arquivo_temp, 'w', encoding='utf-8') as f:
                f.write(resp.text)

            callback_progresso("Instalando atualização...")

            # Faz backup do atual e substitui
            if os.path.exists(arquivo_backup):
                os.remove(arquivo_backup)
            os.rename(arquivo_atual, arquivo_backup)
            os.rename(arquivo_temp, arquivo_atual)

            # Salva versao local para nao pedir de novo
            versao_local = os.path.join(os.path.dirname(arquivo_atual), "versao_local.txt")
            with open(versao_local, "w") as vf:
                vf.write(versao_nova)

            callback_concluido(True, None)
        except Exception as ex:
            callback_concluido(False, str(ex))
    threading.Thread(target=download, daemon=True).start()


class JanelaAtualizacao(tk.Toplevel):
    """Popup de atualização disponível."""

    def __init__(self, parent, versao_nova):
        super().__init__(parent)
        self.parent = parent
        self.versao_nova = versao_nova
        self.title("Atualização Disponível")
        self.configure(bg=BG)
        self.resizable(False, False)
        self.grab_set()

        w, h = 420, 280
        sw, sh = self.winfo_screenwidth(), self.winfo_screenheight()
        self.geometry(f"{w}x{h}+{(sw-w)//2}+{(sh-h)//2}")

        self._build()

    def _build(self):
        # Header
        hdr = tk.Frame(self, bg=VERDE3, pady=14)
        hdr.pack(fill="x")
        tk.Label(hdr, text="🔄  Atualização Disponível!",
                 font=("Georgia", 14, "bold"), bg=VERDE3, fg=OFFWHITE).pack()

        body = tk.Frame(self, bg=BG, padx=24, pady=16)
        body.pack(fill="both", expand=True)

        tk.Label(body,
                 text=f"Uma nova versão do Hope Market PDV está disponível.",
                 font=("Courier", 10), bg=BG, fg=OFFWHITE, wraplength=360,
                 justify="left").pack(anchor="w")
        tk.Label(body,
                 text=f"Versao atual:  {VERSAO_ATUAL}\nVersao nova:   {self.versao_nova}",
                 font=("Courier", 11, "bold"), bg=BG, fg=VERDE2,
                 justify="left").pack(anchor="w", pady=(10,0))

        self.lbl_status = tk.Label(body, text="",
                 font=("Courier", 9), bg=BG, fg=AMARELO)
        self.lbl_status.pack(anchor="w", pady=(8,0))

        # Botões
        rod = tk.Frame(self, bg=BG2, pady=10)
        rod.pack(fill="x", side="bottom")

        self.btn_sim = tk.Button(rod, text="✓  Atualizar agora",
                  font=("Georgia", 11, "bold"), bg=VERDE3, fg=OFFWHITE,
                  relief="flat", padx=16, pady=7, command=self._atualizar)
        self.btn_sim.pack(side="right", padx=14)

        tk.Button(rod, text="Depois", font=("Courier", 10),
                  bg=BG3, fg=CINZA, relief="flat", padx=12, pady=7,
                  command=self.destroy).pack(side="right", padx=4)

    def _atualizar(self):
        self.btn_sim.config(state="disabled", text="⏳ Atualizando...")

        def progresso(msg):
            self.after(0, lambda: self.lbl_status.config(text=msg))

        def concluido(sucesso, erro):
            if sucesso:
                self.after(0, self._pedir_reinicio)
            else:
                self.after(0, lambda: [
                    self.lbl_status.config(text=f"❌ Erro: {erro}", fg=VERMELHO),
                    self.btn_sim.config(state="normal", text="✓  Tentar novamente")
                ])

        baixar_atualizacao(self.versao_nova, progresso, concluido)

    def _pedir_reinicio(self):
        self.destroy()
        if messagebox.askyesno("✓ Atualizado!",
            f"Hope Market PDV atualizado para v{self.versao_nova}!\n\n"
            "É necessário reiniciar o sistema para aplicar.\n\n"
            "Deseja reiniciar agora?"):
            # Reinicia o processo
            import sys, subprocess
            subprocess.Popen([sys.executable, os.path.abspath(__file__)])
            self.parent.quit()

