    # Se nao tem config_unidade.json, abre o wizard primeiro
    if not os.path.exists(_CONFIG_UNIDADE_PATH):
        root.withdraw()  # esconde janela principal
        def iniciar_pdv():
            # Recarrega configuracoes
            import importlib, sys
            global NOME_UNIDADE, SHEETS_ID, ABA_CADASTRO, ESTOQUE_SHEETS_ID, N8N_WEBHOOK
            cfg = _carregar_config_unidade()
            if cfg:
                NOME_UNIDADE      = cfg.get("nome_unidade", NOME_UNIDADE)
                SHEETS_ID         = cfg.get("sheets_id", SHEETS_ID)
                ABA_CADASTRO      = cfg.get("aba_cadastro", ABA_CADASTRO)
                ESTOQUE_SHEETS_ID = cfg.get("estoque_sheets_id", ESTOQUE_SHEETS_ID)
                N8N_WEBHOOK       = cfg.get("n8n_webhook", N8N_WEBHOOK)
            root.deiconify()
            HopeMarketPDV(root)
        WizardUnidade(root, iniciar_pdv)
    else:
        HopeMarketPDV(root)

    root.mainloop()
